import React, { useState } from 'react';

export default function TextForm(props) {

  const [text, setText] = useState('');
  // setText('this keyword is used to update the text keyword, As India act cannot update it directly.');
  const handleUpClick = () => {
    console.log('converting to uppercase' + text);
    let newText = text.toUpperCase();
    setText(newText);
    props.showAlert('converted to upper case', 'success');
  }
  const handleLowClick = () => {
    console.log('converting to uppercase' + text);
    let newText = text.toLowerCase();
    setText(newText);
    props.showAlert('converted to lower case', 'success');
  }
  const handleOnChange = (event) => {
    setText(event.target.value);
  }
  const handleCopy = ()=>{
    var text = document.getElementById('myBox');
    text.select();
    navigator.clipboard.writeText(text.value);
  }

  return (
    <>
    {/* style={{color: props.mode==='dark'?'black':'white'}} */}
    {/* style={{color: props.mode==='dark'?'white':'black'}} */}
      <div className='container' >
        <h1 className='my-3'>{props.heading}</h1>
          <div className="mb-3">
              <label for="myBox" class="form-label">Enter your text here</label>
          <textarea className="form-control" value={text} onChange={handleOnChange} id="myBox" rows="3" 
          // style={{ 
          //     backgroundColor: props.mode === 'dark' ? 'grey' : 'white', 
          //     color: props.mode === 'dark' ? 'white' : 'black' }}
          >
              </textarea>
          </div>
          <button disabled={text.length===0} className="btn btn-primary mx-1 my-1" onClick={handleUpClick}>
            Convert to UpperCase
          </button>
          <button disabled={text.length === 0} className="btn btn-primary mx-1 my-1" onClick={handleLowClick}>
            Convert to LowerCase
          </button>
          <button disabled={text.length === 0} className="btn btn-primary mx-1 my-1" onClick={handleCopy}>
            Copy Text
          </button>
      </div>
      <div className="container" 
        // style={{ color: props.mode === 'light' ? 'white' : 'black' }}
      >
          <h1>your text summary : </h1>
          <p>
              {text.split(' ').filter((element)=>{
                return element.length!==0;
              }).length} words and {text.length} characters
              <br />
          {0.008 * text.split(' ').filter((element) => {
            return element.length !== 0;
          }).length} minutes read
          </p>
          <h3>preview</h3>
          <p>
              {text.length>0?text:'Seems kinda empty here...😔'}
          </p>
      </div>
    </>
  )
}