import React from 'react';
import './App.css';
import Navbar from './components/Navbar';
import TextForm from './components/TextForm';
import About from './components/About';
import { useState } from 'react';
import Alert from './components/Alert';
// import {
//   BrowserRouter as Router,
//   Switch,
//   Route
// } from "react-router-dom";

function App() {
  const [mode, setMode] = useState('light'); // Else with a dark mode is enabled or not

  const [alert, setAlert] = useState(' ');

  const showAlert = (message, type) => {
    setAlert({
      message: message,
      type: type
    })
    setTimeout(() => {
      setAlert(null);
    }, 3000);
  }

  const toggleMode = () => {
    if(mode === 'light') {
      setMode('dark');
      document.body.style.backgroundColor = 'black';
      showAlert('dark mode has been unabled', 'success');
    }
    else {
      setMode('light');
      document.body.style.backgroundColor = 'white';
      showAlert('light mode has been unabled', 'success');
    }
  }

  return (
    <>
        <Navbar title='Text Utility App' aboutText='AboutUs' mode={mode} toggleMode={toggleMode}></Navbar>
        <Alert alert={alert}/>
        {/* <Router>
          <Switch>
        <Route exact path="/about"> */}
        {/* </Route>
        <Route exact path="/"> */}
            <TextForm showAlert={showAlert} heading='Text Utility App - Word counter, character counter, word converter, Lowercase to uppercase, Uppercase lowercase'></TextForm>
        {/* </Route>
          </Switch>
        </Router> */}
      <About mode={mode}></About>
    </>
  );
}
export default App;